import{_ as a,o as r,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Safari Error: Safari cannot open this page because address is invalid","description":"","frontmatter":{"title":"Safari Error: Safari cannot open this page because address is invalid","slug":"safari-error-safari-cannot-open-this-page-because-address-is-invalid"},"headers":[],"relativePath":"marketer-hub/safari-error-safari-cannot-open-this-page-because-address-is-invalid.md","filePath":"marketer-hub/safari-error-safari-cannot-open-this-page-because-address-is-invalid.md"}'),t={name:"marketer-hub/safari-error-safari-cannot-open-this-page-because-address-is-invalid.md"};function s(n,e,c,l,d,h){return r(),i("div",null,[...e[0]||(e[0]=[o('<p>This Safari error (“Safari cannot open this page because address is invalid”) is almost always because of a caching error.</p><h2 id="troubleshoot" tabindex="-1">Troubleshoot <a class="header-anchor" href="#troubleshoot" aria-label="Permalink to &quot;Troubleshoot&quot;">​</a></h2><p>Try the following troubleshooting steps to resolve the error.</p><h3 id="quick-fixes" tabindex="-1">Quick fixes <a class="header-anchor" href="#quick-fixes" aria-label="Permalink to &quot;Quick fixes&quot;">​</a></h3><p>Try the following device-level fixes before moving on to configuration changes:</p><ul><li><strong>Clear Safari cache</strong>: Go to <strong>Settings</strong> &gt; <strong>Safari</strong> &gt; <strong>Clear History and Website Data</strong> to clear your cache in Safari. This forces Safari to re-evaluate its stored redirects.</li><li><strong>Use Private Browsing</strong>: Open a Private Browsing window in Safari to test. Safari’s Private Browsing ignores existing caching and behaviors.</li><li><strong>Wait and retry</strong>: Sometimes, the issue is a delay in Apple&#39;s services propagating the app&#39;s installation status. Wait for 5-10 minutes after an install/uninstall cycle before testing again.</li></ul><h3 id="configuration-fix" tabindex="-1">Configuration fix <a class="header-anchor" href="#configuration-fix" aria-label="Permalink to &quot;Configuration fix&quot;">​</a></h3><p>If device-level fixes don’t resolve the error, try the following configuration fix:</p><h4 id="verify-your-uri-scheme-is-correctly-configured" tabindex="-1">Verify your URI scheme is correctly configured <a class="header-anchor" href="#verify-your-uri-scheme-is-correctly-configured" aria-label="Permalink to &quot;Verify your URI scheme is correctly configured&quot;">​</a></h4><p>The error can also happen if there&#39;s a mismatch between the URI scheme defined in your app and the one entered in the Branch Dashboard.</p><ol><li><strong>Check your app&#39;s</strong> <code>Info.plist</code><strong>:</strong> Find the <code>URL types</code> entry and confirm the exact string used in <code>URL Schemes</code>. It&#39;s case-sensitive.</li><li><strong>Check your Branch Dashboard:</strong> Navigate to <strong>Configuration</strong> &gt; <strong>Link Settings</strong> &gt; <strong>URI Scheme</strong> and ensure the value there exactly matches the one from your <code>Info.plist</code>. A single typo will cause failure.</li></ol>',11)])])}const u=a(t,[["render",s]]);export{g as __pageData,u as default};
